// ──────────────────────────────────────────────
// Midas: 构建最终发布 Payload
// 输入: Sherlock 核查通过的 Markdown 内容
// 输出: /api/ai-publish 的标准请求体
// ──────────────────────────────────────────────

const data = $input.first().json;

// 从内容中提取第一行作为标题（如果不是中文标题则生成一个）
const firstLine = (data.content || '').split('\n').find(l => l.trim()) || '';
const title = firstLine.replace(/^#+\s*/, '').substring(0, 100) || 'AI 自动生成内容';

// 根据内容主题智能选择 subreddit
function guessSubreddit(content) {
  const c = content.toLowerCase();
  if (c.includes('ap') || c.includes('advanced placement')) return 'APExams';
  if (c.includes('a-level') || c.includes('alevel') || c.includes('a level')) return 'ALevel';
  if (c.includes('ib') || c.includes('international baccalaureate')) return 'IBDiploma';
  if (c.includes('sat') || c.includes('act')) return 'SATPrep';
  if (c.includes('toefl') || c.includes('ielts')) return 'EnglishTests';
  if (c.includes('牛剑') || c.includes('oxbridge') || c.includes('牛津') || c.includes('剑桥')) return 'Oxbridge';
  if (c.includes('竞赛') || c.includes('olympiad') || c.includes('bpho') || c.includes('amc')) return 'Competitions';
  return 'AcademicDaily';
}

return {
  secret_key: $env.AI_WEBHOOK_SECRET,
  title: title,
  content: data.content,
  subredditName: guessSubreddit(data.content || ''),
  authorRole: 'Midas'
};

// ──────────────────────────────────────────────
// Midas: 解析发布结果
// ──────────────────────────────────────────────

const response = $input.first().json;

return {
  success: true,
  post_id: response.id,
  subreddit: response.subredditName,
  author: response.authorRole,
  published_at: new Date().toISOString(),
  preview_url: `http://localhost:3000/r/${response.subredditName}/post/${response.id}`
};
